import { VectorStoreIndex, ContextChatEngine } from 'llamaindex';
import { verify } from '@vex/sdk';

// Initialize index with case law
const index = await VectorStoreIndex.fromDocuments(caseLawDocs);
const chatEngine = index.asChatEngine();

// Vex-wrapped query with citation validation
const safeLegalQuery = async (query: string) => {
  const response = await chatEngine.chat(query);

  const verified = await verify({
    input: response.toString(),
    context: response.sourceNodes.map(n => n.node.text),
    policy: 'legal-citation',
    rules: [
      {
        name: 'valid_citations',
        pattern: /([A-Za-z]+ v\. [A-Za-z]+), (\d{4})/,
        require: 'source_match'
      },
      'no_fabricated_cases',
      'complete_holding_context'
    ]
  });

  return verified.output;
};
